demo_filter_input.styleConfig:
#domId { padding-top: 18px; }
#domId .el-input__inner {
  height: 40px;
  line-height: 40px;
  border: 1px solid #cbd5e1;
  border-radius: 6px;
  background: #f8fafc;
  color: #0f172a;
  box-shadow: inset 0 1px 2px rgba(15,23,42,0.04);
}
#domId .el-input__inner:focus {
  border-color: #2563eb;
  box-shadow: 0 0 0 2px rgba(37,99,235,0.12);
}

demo_query_button.styleConfig:
#domId { padding-top: 18px; }
#domId button {
  height: 40px;
  padding: 0 18px;
  background: #2563eb;
  color: #ffffff;
  border: 1px solid #2563eb;
  border-radius: 6px;
  font-size: 14px;
  font-weight: 600;
  box-shadow: 0 8px 18px rgba(37,99,235,0.18);
}
#domId button:hover {
  background: #1d4ed8;
  border-color: #1d4ed8;
}

demo_table.styleConfig:
#domId {
  background: #ffffff;
  border: 1px solid #dbe4f0;
  border-radius: 8px;
  padding: 8px;
  box-sizing: border-box;
}
#domId .el-table__header th,
#domId .el-table__header tr {
  background: #eff6ff;
  color: #0f172a;
  font-weight: 600;
}
#domId .el-table__body tr:nth-child(even) {
  background: #f8fafc;
}
#domId .el-table__body td {
  color: #1f2937;
}
#domId .el-table::before {
  display: none;
}
